ee:message.ee:set-payload:
%dw 2.0 output text/plain
var pe = payload.event
// MSH Fields var sendingApp = "HEALTHFUSION^1266378" var sendingFacility = "NEXTGENOFFICE^1266378" var receivingApp = "FORESTHMS" var receivingFacility = "FORESTHMS^1266378"
// Identifiers var placerId = if (pe.Placer_Appointment_ID__c != null and !isEmpty(pe.Placer_Appointment_ID__c)) pe.Placer_Appointment_ID__c as String else "" var fillerId = pe.NextGen_ID__c as String var patientIdRaw = pe.Patient_ID__c as String var pid = if (patientIdRaw startsWith "HF") patientIdRaw[2 to -1] else patientIdRaw
// Patient name and demographic var patientLastName = (pe.Patient_Last_Name__c as String) default "" var patientFirstName = (pe.Patient_First_Name__c as String) default "" var dobIn = pe.Patient_DOB__c as String var dob = (dobIn as Date {format:"yyyyMMdd"}) as String {format:"yyyyMMdd"} // expects 'yyyyMMdd' var genderVal = upper(pe.Patient_Gender__c as String) var gender = if (genderVal == "FEMALE") "F" else if (genderVal == "MALE") "M" else genderVal var addressStreet = (pe.Patient_Street__c as String) default "" var addressCity = (pe.Patient_City__c as String) default "" var addressState = (pe.Patient_State__c as String) default "" var addressZip = (pe.Patient_Zip__c as String) default ""
// Phone construction, PID-13 var phone = (pe.Patient_Phone__c as String) default "" var phoneDigits = if (sizeOf(phone) == 10) "(" ++ phone[0 to 2] ++ ")" ++ phone[3 to 5] ++ "-" ++ phone[6 to 9] else "" var pid13 = phoneDigits ++ "^^^^^" ++ (if (!isEmpty(phone) and sizeOf(phone) == 10) phone[0 to 2] else "") ++ "^" ++ (if (!isEmpty(phone) and sizeOf(phone) == 10) phone[3 to 9] else "")
// Language - strict var language = (pe.Patient_Language__c as String) default "EN"
// Appointment fields var startDT = (pe.Start_DateTime__c as DateTime {format:"yyyyMMddHHmmss"}) var schStartStr = (startDT as String {format:"yyyyMMddHHmmss"}) var duration = pe.Duration_Value__c as Number var schEndDT = startDT + (duration * 60000) var schEndStr = (schEndDT as DateTime) as String {format:"yyyyMMddHHmmss"} var apptType = (pe.Appointment_Type__c as String) default "" var reason = (pe.Appointment_Reason__c as String) default ""
// Provider & Location var providerNpi = (pe.Provider_NPI__c as String) default "" var providerLast = upper((pe.Provider_Last_Name__c as String) default "") var providerFirst = upper((pe.Provider_First_Name__c as String) default "") var locationId = (pe.Location_ID__c as String) default "" var locationName = upper((pe.Location_Name__c as String) default "")
// Status strict map var statusRaw = upper((pe.Appointment_Status__c as String) default "") var status = if (statusRaw == "SCHEDULED") "NEW" else if (statusRaw == "RESCHEDULED") "RESCHEDULED" else if (statusRaw == "CHECKED OUT") "CHECKED OUT" else if (statusRaw == "CHECKED IN") "CHECKED IN" else if (statusRaw == "CANCELLED BY PROVIDER") "CANCELLED" else if (statusRaw == "NO SHOW") "NO SHOW" else statusRaw
--- ( // MSH "MSH|^~\\&|" ++ sendingApp ++ "|" ++ sendingFacility ++ "|" ++ receivingApp ++ "|" ++ receivingFacility ++ "|" ++ now() as String {format:"yyyyMMddHHmmss"} ++ "||SIU^S12|" ++ fillerId ++ "|P|2.3" // SCH ++ "\nSCH|" ++ placerId ++ "|" ++ fillerId ++ "||||" ++ apptType ++ "|" ++ reason ++ "|" ++ apptType ++ "|" ++ (duration as String) ++ "|MIN|^^^" ++ schStartStr ++ "^" ++ schEndStr ++ "|||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "|||||||||" ++ status // PID ++ "\nPID|1|" ++ pid ++ "|" ++ pid ++ "|HF" ++ pid ++ "|" ++ upper(patientLastName) ++ "^" ++ upper(patientFirstName) ++ "|" ++ "|" // Mother's maiden name ++ dob ++ "|" ++ gender ++ "|" ++ "|" // PID-9 ++ "PATIENT DECLINED|" // PID-10 ++ addressStreet ++ "^^" ++ addressCity ++ "^" ++ addressState ++ "^" ++ addressZip ++ "|" ++ pid13 ++ "||" ++ language ++ "|||||||PATIENT DECLINED" // PV1 ++ "\nPV1|1|O|^^^" ++ locationId ++ "^^^^^" ++ locationName ++ "||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "||||1275017^^^1275017^^^^^FOREST HILLS||||||||" ++ fillerId ++ "||||||||||||||||||||1266378;FOREST HILLS MEDICAL SERVICES;FORESTHMS|||||" ++ schStartStr ++ "|" ++ schEndStr // RGS ++ "\nRGS|" // AIL ++ "\nAIL|1||" ++ locationId ++ "^^^" ++ locationName // AIP ++ "\nAIP|1||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst )

%dw 2.0  
output text/plain  

var pe = payload.event  

var apptId        = pe.NextGen_ID__c as String  
var pid           = if ((pe.Patient_ID__c as String) startsWith "HF") (pe.Patient_ID__c as String)[2 to -1] else (pe.Patient_ID__c as String)  
var dob           = (pe.Patient_DOB__c as Date {format:"MMMM dd, yyyy"}) as String {format:"yyyyMMdd"}  
var gender        =  
  if (pe.Patient_Gender__c as String == "Female") "F"  
  else if (pe.Patient_Gender__c as String == "Male") "M"  
  else "U"  

var phone         = pe.Patient_Phone__c as String  
var phoneFormatted=  
  if (sizeOf(phone) == 10)  
    "(" ++ phone[0 to 2] ++ ")" ++ phone[3 to 5] ++ "-" ++ phone[6 to 9]  
  else phone  
var area          = if (sizeOf(phone) >= 3) phone[0 to 2] else ""  
var rest          = if (sizeOf(phone) >= 7) phone[3 to 9] else ""  
var contactInfo   = phoneFormatted ++ "^^^" ++ "^^" ++ area ++ "^" ++ rest  

var statusRaw     = pe.Appointment_Status__c as String  
var status =  
  if (statusRaw == "Cancelled by Provider") "CANCELLED"  
  else if (statusRaw == "No Show") "NO SHOW"  
  else if (statusRaw == "RESCHEDULED") "RESCHEDULED"  
  else if (statusRaw == "Checked Out") "CHECKED OUT"  
  else if (statusRaw == "Checked In") "CHECKED IN"  
  else if (statusRaw == "Scheduled") "NEW"  
  else statusRaw  

var schStart      = (pe.Start_DateTime__c as DateTime {format:"M/d/yyyy h:mm a"})  
var schStartStr   = (schStart as String {format:"yyyyMMddHHmmss"})  
var schEnd        = schStart + ((pe.Duration_Value__c as Number) * 60000)  
var schEndStr     = (schEnd as String {format:"yyyyMMddHHmmss"})  

var providerNpi   = pe.Provider_NPI__c as String  
var providerLast  = upper(pe.Provider_Last_Name__c as String)  
var providerFirst = upper(pe.Provider_First_Name__c as String)  
var apptType      = upper(pe.Appointment_Type__c as String)  
var apptReason    = (pe.Appointment_Reason__c as String)  
var locationId    = pe.Location_ID__c as String  
var locationName  = upper(pe.Location_Name__c as String)  
var patientLast   = upper(pe.Patient_Last_Name__c as String)  
var patientFirst  = upper(pe.Patient_First_Name__c as String)  
var language      = upper(pe.Patient_Language__c as String)  
var patientStreet = upper(pe.Patient_Street__c as String)  
var patientCity   = upper(pe.Patient_City__c as String)  
var patientState  = upper(pe.Patient_State__c as String)  
var patientZip    = upper(pe.Patient_Zip__c as String)  

---  
(  
"MSH|^~\\&|HEALTHFUSION^1266378|NEXTGENOFFICE^1266378|FORESTHMS|FORESTHMS^1266378|" ++ now() as String {format:"yyyyMMddHHmmss"} ++ "||SIU^S15|" ++ apptId ++ "|P|2.3" ++  
"\nSCH||" ++ apptId ++ "||||" ++ apptType ++ "|" ++ apptReason ++ "|" ++ apptType ++ "|" ++ (pe.Duration_Value__c as String) ++ "|MIN|" ++ "^^^" ++ schStartStr ++ "^" ++ schEndStr ++ "|||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "|||||||||" ++ status ++  
"\nPID|1|" ++ pid ++ "|" ++ pid ++ "|HF" ++ pid ++ "|" ++ patientLast ++ "^" ++ patientFirst ++ "|" ++ "|" ++ dob ++ "|" ++ gender ++ "|" ++ "|" ++ "PATIENT DECLINED|" ++ patientStreet ++ "^^" ++ patientCity ++ "^" ++ patientState ++ "^" ++ patientZip ++ "|" ++ contactInfo ++ "||" ++ language ++ "|||||||PATIENT DECLINED" ++  
"\nPV1|1|O|^^^" ++ locationId ++ "^^^^^" ++ locationName ++ "||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "||||1275017^^^1275017^^^^^FOREST HILLS||||||||" ++ apptId ++ "||||||||||||||||||||1266378;FOREST HILLS MEDICAL SERVICES;FORESTHMS|||||" ++ schStartStr ++ "|" ++ schEndStr ++  
"\nRGS|" ++  
"\nAIL|1||" ++ locationId ++ "^^^" ++ locationName ++  
"\nAIP|1||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst  
)
